class Car:
    def __init__(self, position: float, speed: float):
        self.position = position
        self.speed = speed
        self.crashed = False

class Track:
    def __init__(self, cars: List[Tuple[float, float]], after_collision_speed: float):
        self.cars = sorted(cars, key=lambda x: x[0])
        self.after_collision_speed = after_collision_speed

    def advance(self):
        for car in self.cars:
